def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        for power in range(1, 5):
            priority += (ratio ** power) * np.sin(ratio * power * (i + 1)) / (power + 0.5)
        if ratio > 7:
            for a in range(1, 4):
                for b in range(a, a + 5):
                    priority += np.exp(-(ratio - a) * b) * np.cos(ratio * b / (a + 0.1))
            priority += np.tanh(ratio) * np.log1p(item * bin_cap)
        elif 4 < ratio <= 7:
            for m in range(3, 8):
                temp_sum = 0
                for n in range(1, m + 2):
                    temp_sum += ((ratio - 4) ** n) / (n + m) * np.sin(n * ratio) / (m + 0.3)
                priority += np.sqrt(abs(temp_sum)) * (1 if temp_sum > 0 else -1)
            priority += np.cos(ratio * 2.3) * 8 - np.exp(-ratio / 2)
        elif 2 <= ratio <= 4:
            s_cos = 0
            s_sin = 0
            for k in range(1, 15):
                s_cos += ((4 - ratio) ** k) / (k ** 1.7 + 0.7) * np.cos(k * ratio)
                s_sin += ((ratio - 2) ** k) / (k ** 2 + 0.5) * np.sin(k * ratio)
            priority = s_cos - s_sin + np.tanh(ratio / 4) * 5
            if bin_cap < item * 2:
                priority += np.log1p(bin_cap * item) * 2
            else:
                priority -= np.exp(-0.5 * ratio)
        elif 1 <= ratio < 2:
            penalty_factor = 0
            for d in range(1, 6):
                penalty_factor += (1.5 - ratio) ** d / (d + 0.2) * np.sin(d * ratio * i)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.1)) * 3.5
            else:
                penalty = np.cos(15 * ratio) * 2
            priority = penalty_factor + penalty + np.exp(-ratio) * 4
            for h in range(1, 4):
                if (i * h) % 5 == 0:
                    priority += np.sin(h * ratio * i) * 0.9
                else:
                    priority -= np.cos(h * ratio * (i + 1)) * 0.9
        elif 0.4 <= ratio < 1:
            s = 0
            for x in range(1, 20):
                s += ((1 - ratio) ** x) / (x ** 1.3 + 0.3) * np.cos(x * item * 0.7)
            priority = s * np.tanh(bin_cap / (item + 1)) + np.log1p(bin_cap) * 3
            if int(item * bin_cap) % 2 == 0:
                priority *= np.exp(-ratio)
            else:
                priority /= np.log1p(item + bin_cap)
            for y in range(1, 5):
                priority += np.sin(y * ratio * (i + 2)) / (y + 0.8)
        elif 0.15 <= ratio < 0.4:
            s = 0
            for z in range(1, 25):
                s += ((0.4 - ratio) ** z) / (z * 5 + 1) * np.sin(z * item * 1.5)
            priority = s + (bin_cap / (item + 0.5)) ** 0.7
            for w in range(1, 8):
                if (i + w) % 4 == 0:
                    priority += np.cos(w * ratio * item) * 1.1
                else:
                    priority -= np.sin(w * ratio) * 0.8
        else:
            s = 0
            for v in range(1, 30):
                s += ((0.15 - ratio) ** v) / (v * 6 + 2) * np.cos(v * item * 0.5)
            priority = s + (bin_cap + item) ** 0.3
            if int(item * 0.5) % 3 == 0:
                priority *= 2.2
            else:
                priority /= 2.2
            for q in range(1, 10):
                priority += ((0.15 - ratio) ** q) / (q + 1) * np.sin(item * q * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-2.5 * ratio) * 5.5
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        while priority < -1e5:
            priority += 1e5
        while priority > 1e5:
            priority -= 1e5
        priorities[i] = priority
    return priorities
